            toStringOutput.Add($"BroadInfo = {(this.BroadInfo == null ? "null" : this.BroadInfo.ToString())}");
            toStringOutput.Add($"MessageExtension = {(this.MessageExtension == null ? "null" : $"[{string.Join(", ", this.MessageExtension)} ]")}");
            toStringOutput.Add($"ChallengeMessageExtension = {(this.ChallengeMessageExtension == null ? "null" : $"[{string.Join(", ", this.ChallengeMessageExtension)} ]")}");
            toStringOutput.Add($"BrowserInformation = {(this.BrowserInformation == null ? "null" : this.BrowserInformation.ToString())}");
            toStringOutput.Add($"ThreeRiInd = {(this.ThreeRiInd == null ? "null" : this.ThreeRiInd.ToString())}");
            toStringOutput.Add($"Device = {(this.Device == null ? "null" : this.Device.ToString())}");
            toStringOutput.Add($"MultiTransaction = {(this.MultiTransaction == null ? "null" : this.MultiTransaction.ToString())}");
            toStringOutput.Add($"DeviceId = {this.DeviceId ?? "null"}");
            toStringOutput.Add($"UserId = {this.UserId ?? "null"}");
            toStringOutput.Add($"PayeeOrigin = {this.PayeeOrigin ?? "null"}");

            base.ToString(toStringOutput);
        }
    }
}